create table public.profiles (id uuid primary key references auth.users(id), full_name text, role text default 'editor', created_at timestamptz default now());
create table public.authors (id uuid primary key default gen_random_uuid(), name text not null, bio text, avatar_url text, created_at timestamptz default now());
create table public.categories (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, description text);
create table public.stories (id uuid primary key default gen_random_uuid(), title text not null, slug text not null unique, description text, author_id uuid references public.authors(id), category_id uuid references public.categories(id), age_range text, reading_time integer, theme text, cover_url text, status text default 'draft', views integer default 0, created_at timestamptz default now(), published_at timestamptz);
create table public.story_pages (id uuid primary key default gen_random_uuid(), story_id uuid references public.stories(id) on delete cascade, page_number integer not null, image_url text, content text);
create table public.favorites (user_id uuid references auth.users(id), story_id uuid references public.stories(id) on delete cascade, created_at timestamptz default now(), primary key(user_id, story_id));
create table public.comments (id uuid primary key default gen_random_uuid(), story_id uuid references public.stories(id) on delete cascade, user_id uuid references auth.users(id), content text not null, status text default 'pending', created_at timestamptz default now());
alter table public.stories enable row level security;alter table public.favorites enable row level security;alter table public.comments enable row level security;
create policy "Published stories are public" on public.stories for select using (status='published' or auth.uid() is not null);
create policy "Users manage favorites" on public.favorites for all using (auth.uid()=user_id) with check (auth.uid()=user_id);
insert into storage.buckets (id,name,public,file_size_limit,allowed_mime_types) values ('stories','stories',true,52428800,array['application/pdf','application/vnd.openxmlformats-officedocument.wordprocessingml.document','image/png','image/jpeg','image/webp']);
